import org.owasp.encoder.Encode;

public class SecureCode {
    public static void main(String[] args) {
        // Simulating user input from a form
        String userInput = "<script>alert('XSS attack!')</script>";

        // Encoding user input to prevent XSS
        String encodedUserInput = Encode.forHtml(userInput);

        // Displaying properly encoded user input on a web page
        System.out.println("<p>User Input: " + encodedUserInput + "</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
